import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"PRD-003 — Mission Arc","description":"","frontmatter":{},"headers":[],"relativePath":"prd/PRD-003.md","filePath":"prd/PRD-003.md"}'),r={name:"prd/PRD-003.md"};function o(n,e,l,h,c,d){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="prd-003-—-mission-arc" tabindex="-1">PRD-003 — Mission Arc <a class="header-anchor" href="#prd-003-—-mission-arc" aria-label="Permalink to &quot;PRD-003 — Mission Arc&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Sources · 02_Project_Concept.md §six-screens · ADR-009 · ADR-010 Audiences · curious learner, STEM student (PA §audiences) Promises · real physics, educational at every level, fail honestly (PA §promises) Principles · physics first, prototype is ground truth (PA §principles) Why this is a PRD · The fly screen is where the physics becomes visceral — the spacecraft actually moves, the distance grows, the signal delay becomes emotional. CAPCOM mode adds the flight controller perspective. This screen is the culmination of the Orrery narrative.</p></blockquote><p>509 days. A person is watching a small white chevron move across a curved arc. The distance from Earth is 187 million kilometres. The signal delay is 10.4 minutes. They press CAPCOM. An event ticker appears. &quot;T+259d · MARS FLYBY · Closest approach: 300 km altitude. Gravity assist initiates return.&quot; The chevron is past Mars now. It is on its way home.</p><h2 id="the-problem" tabindex="-1">The problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The problem&quot;">​</a></h2><p>Every Mars mission launches, flies for months, arrives, and does science. The transit — 259 days of deep space cruise — is invisible. There are no images. There is nothing to show. The public understands launches and landings. The 180 million kilometres in between is a blank.</p><p>The free-return flyby makes the transit the story. The spacecraft leaves Earth, swings around Mars, and comes home. 509 days. The arc is visible. The signal delay is measurable. The mission has a shape.</p><h2 id="the-experience" tabindex="-1">The experience <a class="header-anchor" href="#the-experience" aria-label="Permalink to &quot;The experience&quot;">​</a></h2><p>The screen opens on a 3D view. The Sun is at the centre. Earth and Mars orbit in real time. A transfer arc connects them — the outbound leg in blue, the return leg in violet. A white rocket icon moves along the arc, oriented along its velocity vector.</p><p>The HUD shows heliocentric velocity (updating from vis-viva), distance from Earth in millions of km and light-minutes, distance from Mars, fuel percentage, estimated arrival, and mission phase.</p><p>The user switches to 2D. The orbital view is top-down. The full free-return trajectory is visible — outbound arc solid blue, return arc solid violet, future path dashed. FLYBY and RETURN markers label the endpoints. The rocket chevron points along its direction of travel.</p><p>The user presses CAPCOM. Three panels appear alongside the left HUD. The mission event ticker shows all 13 events from LAUNCH to EARTH RETURN, ticking off as time advances. The communications panel shows &quot;LAST TELEMETRY: 10.4 min ago&quot; in real-time — the one-way signal delay computed from the actual Earth distance. The anomaly monitor watches fuel and delta-v margin.</p><p>The user speeds up to 90 days/second. The Mars flyby arrives — a pulsing ring appears briefly at closest approach. The return leg begins. Earth grows. The ticker counts down.</p><h2 id="why-now" tabindex="-1">Why now <a class="header-anchor" href="#why-now" aria-label="Permalink to &quot;Why now&quot;">​</a></h2><p>The fly screen is Act 3 — the culmination. The explorer showed the geometry, the configurator showed the cost, and the fly screen shows what it actually looks like to cross that geometry. Without it, the mission planning exercise has no payoff.</p><h2 id="success-looks-like" tabindex="-1">Success looks like <a class="header-anchor" href="#success-looks-like" aria-label="Permalink to &quot;Success looks like&quot;">​</a></h2><p>A user watches the signal delay grow from 3 minutes to 11 minutes over the outbound arc and says &quot;I never understood why communicating with Mars is so hard until now.&quot;</p><p>A student uses the CAPCOM ticker to identify the TMI burn, the flyby, and the return trajectory initiation, and can explain what each event means.</p><p>A user is emotionally present during the Mars flyby — the pulsing marker and the CAPCOM event create a genuine sense of occasion.</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Mars orbit insertion (free-return trajectory only in v1 — ADR-009)</li><li>Real historical mission telemetry (ORRERY-1 is a fictional free-return scenario)</li><li>Audio</li><li>Multiplayer / shared viewing</li></ul><h2 id="the-sharpest-threat" tabindex="-1">The sharpest threat <a class="header-anchor" href="#the-sharpest-threat" aria-label="Permalink to &quot;The sharpest threat&quot;">​</a></h2><p>The CAPCOM mode adds complexity without adding clarity if the event notes are generic. &quot;Trajectory correction manoeuvre&quot; means nothing to a curious learner. Each event note must be written in plain language that makes the event feel real — what it means, why it happens, what it changes.</p><h2 id="open-threads" tabindex="-1">Open threads <a class="header-anchor" href="#open-threads" aria-label="Permalink to &quot;Open threads&quot;">​</a></h2><ul><li>UXS-003 for full visual contract</li><li>RFC-002 for events array schema in mission JSON</li><li>RFC-004 for URL sharing (<code>/fly?mission=id</code>)</li><li>ADR-009 locks free-return flyby as the scenario</li><li>ADR-010 locks Keplerian arcs</li></ul><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Prototype: <code>docs/prototypes/P03_mission-arc.html</code></li><li>Concept: <code>docs/concept/02_Project_Concept.md §six-screens</code></li></ul>',26)])])}const m=a(r,[["render",o]]);export{p as __pageData,m as default};
